#include <iostream>
using namespace std;

class Person {
protected:
 string name;
 int age;
public:
 Person(string n, int a) : name(n), age(a) {
 cout << "Person Constructor: " << name << endl;
 }
 ~Person() {
 cout << "Person Destructor: " << name << endl;
 }
 void display() {
 cout << "Name: " << name << ", Age: " << age << endl;
 }
};

class Student : public Person {
private:
 int rollNo;
 float marks;
public:
 Student(string n, int a, int r, float m) : Person(n, a), rollNo(r), marks(m) {
 cout << "Student Constructor" << endl;
 }
 ~Student() {
 cout << "Student Destructor" << endl;
 }
 void show() {
 display();
 cout << "Roll No: " << rollNo << ", Marks: " << marks << endl;
 }
};

int main() {
 Student s("John", 20, 101, 85.5);
 s.show();
 return 0;
}

#include <iostream>
using namespace std;

class Base1 {
protected:
 int x;
public:
 Base1() : x(10) {}
 void show() { cout << "Base1: x = " << x << endl; }
};

class Base2 {
protected:
 int y;
public:
 Base2() : y(20) {}
 void show() { cout << "Base2: y = " << y << endl; }
};

class Derived : public Base1, public Base2 {
public:
 void display() {
 // Ambiguity - which show()?
 // Using scope resolution to resolve
 Base1::show();
 Base2::show();
 cout << "Sum: " << x + y << endl;
 }
};

int main() {
 Derived d;
 d.display();
 // d.show(); // ERROR - ambiguous!
 return 0;
}

#include <iostream>
using namespace std;

class Base {
protected:
 int data;
public:
 Base() : data(100) {
 cout << "Base Constructor" << endl;
 }
 void show() { cout << "Base data: " << data << endl; }
};

// Virtual inheritance - prevents duplication
class Derived1 : virtual public Base {
public:
 Derived1() { cout << "Derived1 Constructor" << endl; }
};

class Derived2 : virtual public Base {
public:
 Derived2() { cout << "Derived2 Constructor" << endl; }
};

// Most derived class
class MostDerived : public Derived1, public Derived2 {
public:
 MostDerived() { cout << "MostDerived Constructor" << endl; }
};

int main() {
 MostDerived md;
 md.show(); // No ambiguity - only one Base exists!
 cout << "Size of MostDerived: " << sizeof(md) << endl;
 return 0;
}

#include <iostream>
using namespace std;

class Base {
public:
 int a;
protected:
 int b;
private:
 int c;
};

class Derived : protected Base {
 // public a becomes protected
 // protected b remains protected
 // private c inaccessible
public:
 void access() {
 a = 10; // OK - was public, now protected but accessible here
 b = 20; // OK - protected remains protected
 // c = 30; // ERROR - private members never accessible
 }
};

class GrandDerived : public Derived {
public:
 void access2() {
 a = 10; // OK - accessible in further derived class
 b = 20; // OK - protected remains protected
 }
};

int main() {
 Derived d;
 // d.a = 5; // ERROR - a is now protected in Derived
 // d.b = 10; // ERROR - b is protected
 return 0;
}
